Consider the following code:

class InvalidAgeException : public std::runtime_error {
public:
    InvalidAgeException(int age) : std::runtime_error("Invalid age"), ageValue(age) {}
    int getAge() const { return ageValue; }
private:
    int ageValue;
};

void setAge(int age) {
    if (age < 0 || age > 150)
        throw InvalidAgeException(age);
}

What is the correct way to catch this exception?

